# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, name):
        self.name = name
        self.balance = 0.0

def process_transactions(transactions):
    accounts = {}
    
    for transaction in transactions:
        if transaction['account'] not in accounts:
            accounts[transaction['account']] = Account(transaction['account'])
        
        if transaction['type'] == 'deposit':
            accounts[transaction['account']].balance += transaction['amount']
        elif transaction['type'] == 'withdrawal':
            accounts[transaction['account']].balance -= transaction['amount']
    
    return accounts

def print_balances(accounts):
    for account in accounts.values():
        print(f"Account: {account.name}, Balance: {account.balance}")

# Example usage
transactions = [
    {'account': 'Checking', 'type': 'deposit', 'amount': 1000.0},
    {'account': 'Savings', 'type': 'deposit', 'amount': 500.0},
    {'account': 'Checking', 'type': 'withdrawal', 'amount': 200.0}
]

accounts = process_transactions(transactions)
print_balances(accounts)